#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct { long long cnt0, cnt1, internal; } Node;

int cmp(const void *a, const void *b) {
    const Node *A = (const Node *)a;
    const Node *B = (const Node *)b;
    long long left = A->cnt1 * B->cnt0;
    long long right = B->cnt1 * A->cnt0;
    if (left < right) return -1;
    if (left > right) return 1;
    return 0;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, M; scanf("%d %d", &N, &M);
        Node *arr = (Node*)malloc(N * sizeof(Node));
        char *buf = (char*)malloc((M+5) * sizeof(char));
        long long totalInternal = 0;
        for(int i=0;i<N;i++){
            scanf("%s", buf);
            long long c0=0, c1=0, inv=0;
            for(int j=0;j<M;j++){
                if(buf[j]=='1') c1++;
                else { // '0'
                    c0++;
                    inv += c1; // each previous '1' forms an inversion with this '0'
                }
            }
            arr[i].cnt0 = c0;
            arr[i].cnt1 = c1;
            arr[i].internal = inv;
            totalInternal += inv;
        }
        qsort(arr, N, sizeof(Node), cmp);
        long long prefOnes = 0, cross = 0;
        for(int i=0;i<N;i++){
            cross += prefOnes * arr[i].cnt0;
            prefOnes += arr[i].cnt1;
        }
        printf("%lld\n", totalInternal + cross);
        free(arr);
        free(buf);
    }
    return 0;
}

