#include <bits/stdc++.h>
using namespace std;
struct Item{
    long long cnt0, cnt1, internal;
};

bool cmp(const Item &a, const Item &b){
    // a before b if a.cnt1 * b.cnt0 < b.cnt1 * a.cnt0
    return a.cnt1 * b.cnt0 < b.cnt1 * a.cnt0;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N, M; cin>>N>>M;
        vector<Item> v(N);
        long long totalInternal = 0;
        string s;
        for(int i=0;i<N;i++){
            cin>>s;
            long long c0=0, c1=0, inv=0;
            for(char ch: s){
                if(ch=='1') c1++;
                else { c0++; inv += c1; }
            }
            v[i] = {c0, c1, inv};
            totalInternal += inv;
        }
        sort(v.begin(), v.end(), cmp);
        long long prefOnes = 0, cross = 0;
        for(const auto &it: v){
            cross += prefOnes * it.cnt0;
            prefOnes += it.cnt1;
        }
        cout << totalInternal + cross << '\n';
    }
    return 0;
}

