import java.io.*;
import java.util.*;

public class Main {
    static class Item {
        long cnt0, cnt1, internal;
        Item(long c0, long c1, long in){ cnt0=c0; cnt1=c1; internal=in; }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int M = fs.nextInt();
            Item[] arr = new Item[N];
            long totalInternal = 0;
            for (int i = 0; i < N; i++) {
                String s = fs.next();
                long c0 = 0, c1 = 0, inv = 0;
                for (int j = 0; j < M; j++) {
                    char ch = s.charAt(j);
                    if (ch == '1') c1++;
                    else { c0++; inv += c1; }
                }
                arr[i] = new Item(c0, c1, inv);
                totalInternal += inv;
            }
            Arrays.sort(arr, (a, b) -> {
                long left = a.cnt1 * b.cnt0;
                long right = b.cnt1 * a.cnt0;
                return Long.compare(left, right);
            });
            long prefOnes = 0, cross = 0;
            for (Item it : arr) {
                cross += prefOnes * it.cnt0;
                prefOnes += it.cnt1;
            }
            out.append(totalInternal + cross).append('\n');
        }
        System.out.print(out.toString());
    }

    // Fast scanner for Java
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') {
                sb.append((char) c);
                c = readByte();
            }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
}

